        .CE(y),
        .D(y_next[3]),
        .Q(\y_reg_n_0_[3] ),
        .R(RSTP));
  FDRE #(
    .INIT(1'b0)) 
    \y_reg[4] 
       (.C(aclk),
        .CE(y),
        .D(y_next[4]),
        .Q(\y_reg_n_0_[4] ),
        .R(RSTP));
  FDRE #(
    .INIT(1'b0)) 
    \y_reg[5] 
       (.C(aclk),
        .CE(y),
        .D(y_next[5]),
        .Q(\y_reg_n_0_[5] ),
        .R(RSTP));
endmodule
`ifndef GLBL
